  1→/**
  2→ * Category API Client
  3→ *
  4→ * TypeScript client for Category API with fetch wrapper.
  5→ * Provides typed methods for CRUD operations on categories.
  6→ */
  7→
  8→import type {
  9→  CategoryData,
 10→  CategoryListParams,
 11→  CategoryCreateInput,
 12→  CategoryUpdateInput,
 13→  ApiListResponse,
 14→  ApiResponse,
 15→  ApiClientConfig,
 16→} from './types';
 17→import { ApiClientError, parseApiError, parseJson } from './shared';
 18→
 19→export { ApiClientError } from './shared';
 20→
 21→const DEFAULT_BASE_URL = '/api';
 22→
 23→export class CategoryApiClient {
 24→  private baseUrl: string;
 25→  private fetchFn: typeof globalThis.fetch;
 26→  private defaultHeaders: Record<string, string>;
 27→
 28→  constructor(config: ApiClientConfig = {}) {
 29→    this.baseUrl = config.baseUrl ?? DEFAULT_BASE_URL;
 30→    this.fetchFn = config.fetch ?? fetch;
 31→    this.defaultHeaders = {
 32→      'Content-Type': 'application/json',
 33→      ...config.headers,
 34→    };
 35→  }
 36→
 37→  private url(path: string, params?: Record<string, string | undefined>): string {
 38→    const fullUrl = `${this.baseUrl}${path}`;
 39→
 40→    if (params) {
 41→      const searchParams = new URLSearchParams();
 42→      for (const [key, value] of Object.entries(params)) {
 43→        if (value !== undefined) {
 44→          searchParams.append(key, value);
 45→        }
 46→      }
 47→      const queryString = searchParams.toString();
 48→      if (queryString) {
 49→        return `${fullUrl}?${queryString}`;
 50→      }
 51→    }
 52→
 53→    return fullUrl;
 54→  }
 55→
 56→  /**
 57→   * GET /api/categories
 58→   *
 59→   * List categories with optional filters: type, isActive, includeInactive.
 60→   * Returns flat list sorted by parentId (nulls first), then order.
 61→   */
 62→  async getCategories(params?: CategoryListParams): Promise<ApiListResponse<CategoryData>> {
 63→    const queryParams: Record<string, string | undefined> = {};
 64→
 65→    if (params?.type) queryParams.type = params.type;
 66→    if (params?.isActive !== undefined) queryParams.isActive = String(params.isActive);
 67→    if (params?.includeInactive !== undefined) queryParams.includeInactive = String(params.includeInactive);
 68→
 69→    const response = await this.fetchFn(
 70→      this.url('/categories', queryParams),
 71→      { headers: this.defaultHeaders }
 72→    );
 73→
 74→    if (!response.ok) {
 75→      return parseApiError(response);
 76→    }
 77→
 78→    return parseJson<ApiListResponse<CategoryData>>(response);
 79→  }
 80→
 81→  /**
 82→   * GET /api/categories/[id]
 83→   *
 84→   * Fetch a single active category by ID.
 85→   *
 86→   * @param id - Category UUID
 87→   * @returns Category data
 88→   * @throws ApiClientError with 404 if not found
 89→   */
 90→  async getCategory(id: string): Promise<ApiResponse<CategoryData>> {
 91→    if (!id) {
 92→      throw new ApiClientError(400, 'Validation failed', 'id is required');
 93→    }
 94→
 95→    const response = await this.fetchFn(this.url(`/categories/${id}`), {
 96→      headers: this.defaultHeaders,
 97→    });
 98→
 99→    if (!response.ok) {
100→      return parseApiError(response);
101→    }
102→
103→    return parseJson<ApiResponse<CategoryData>>(response);
104→  }
105→
106→  /**
107→   * POST /api/categories
108→   *
109→   * Create a new category.
110→   *
111→   * @param data - Category creation input
112→   * @returns Created category data (status 201)
113→   * @throws ApiClientError with 400 on validation errors (missing name, invalid type, bad parentId)
114→   */
115→  async createCategory(data: CategoryCreateInput): Promise<ApiResponse<CategoryData>> {
116→    const response = await this.fetchFn(this.url('/categories'), {
117→      method: 'POST',
118→      headers: this.defaultHeaders,
119→      body: JSON.stringify(data),
120→    });
121→
122→    if (!response.ok) {
123→      return parseApiError(response);
124→    }
125→
126→    return parseJson<ApiResponse<CategoryData>>(response);
127→  }
128→
129→  /**
130→   * PATCH /api/categories/[id]
131→   *
132→   * Update an existing category (partial update).
133→   * Only provided fields are changed.
134→   *
135→   * @param id - Category UUID
136→   * @param data - Category update input (all fields optional)
137→   * @returns Updated category data
138→   * @throws ApiClientError with 404 if category not found, 400 on validation errors
139→   */
140→  async updateCategory(
141→    id: string,
142→    data: CategoryUpdateInput
143→  ): Promise<ApiResponse<CategoryData>> {
144→    if (!id) {
145→      throw new ApiClientError(400, 'Validation failed', 'id is required');
146→    }
147→
148→    const response = await this.fetchFn(this.url(`/categories/${id}`), {
149→      method: 'PATCH',
150→      headers: this.defaultHeaders,
151→      body: JSON.stringify(data),
152→    });
153→
154→    if (!response.ok) {
155→      return parseApiError(response);
156→    }
157→
158→    return parseJson<ApiResponse<CategoryData>>(response);
159→  }
160→
161→  /**
162→   * DELETE /api/categories/[id]
163→   *
164→   * Soft-delete a category by setting isActive = false.
165→   * Refuses if category is referenced by Budget or Transaction records.
166→   *
167→   * @param id - Category UUID
168→   * @returns Deactivated category data with success message
169→   * @throws ApiClientError with 404 if not found, 409 if referenced
170→   */
171→  async deleteCategory(id: string): Promise<ApiResponse<CategoryData> & { message: string }> {
172→    if (!id) {
173→      throw new ApiClientError(400, 'Validation failed', 'id is required');
174→    }
175→
176→    const response = await this.fetchFn(this.url(`/categories/${id}`), {
177→      method: 'DELETE',
178→      headers: this.defaultHeaders,
179→    });
180→
181→    if (!response.ok) {
182→      return parseApiError(response);
183→    }
184→
185→    return parseJson<ApiResponse<CategoryData> & { message: string }>(response);
186→  }
187→}
