 1→/**
 2→ * Shared API Client Helpers
 3→ *
 4→ * parseApiError, parseJson, and ApiClientError used by all API clients.
 5→ */
 6→
 7→import type { ApiError } from './types';
 8→
 9→/**
10→ * API client error class
11→ */
12→export class ApiClientError extends Error {
13→  constructor(
14→    public statusCode: number,
15→    public error: string,
16→    public message: string
17→  ) {
18→    super(`${error}: ${message}`);
19→    this.name = 'ApiClientError';
20→  }
21→}
22→
23→/**
24→ * Parse and throw API error from response
25→ */
26→export async function parseApiError(response: Response): Promise<never> {
27→  let error: ApiError;
28→
29→  try {
30→    error = await response.json();
31→  } catch {
32→    error = {
33→      error: 'Unknown error',
34→      message: response.statusText || 'Failed to parse error response',
35→    };
36→  }
37→
38→  console.error('API request failed:', response.status, error);
39→  throw new ApiClientError(response.status, error.error, error.message);
40→}
41→
42→/**
43→ * Validate response is JSON and parse it
44→ */
45→export async function parseJson<T>(response: Response): Promise<T> {
46→  const contentType = response.headers.get('content-type');
47→  if (!contentType?.includes('application/json')) {
48→    console.error('Unexpected content-type:', contentType);
49→    throw new ApiClientError(
50→      response.status,
51→      'Invalid response',
52→      'Expected JSON response but got ' + (contentType || 'no content-type')
53→    );
54→  }
55→
56→  return response.json() as Promise<T>;
57→}
